mapper.select:
SELECT u.id, u.username, u.nickname, u.email, u.phone, u.status, u.create_time, GROUP_CONCAT(ur.role_id) as role_ids, GROUP_CONCAT(r.role_name) as role_names FROM mtp_user u LEFT JOIN mtp_user_role ur ON u.id = ur.user_id LEFT JOIN mtp_role r ON ur.role_id = r.id
AND u.username LIKE CONCAT('%', #{username}, '%')
GROUP BY u.id, u.username, u.nickname, u.email, u.phone, u.status, u.create_time ORDER BY u.create_time DESC LIMIT #{offset}, #{limit}
